#include <assert.h>
#include <string.h>
#include <stdio.h>
#include "zlib.h"

void test_compress_decompress(void) {
    const char *original = "Hello, zlib compression test!";
    uLong src_len = strlen(original) + 1;
    uLong dest_len = compressBound(src_len);

    Bytef *compressed = (Bytef *)malloc(dest_len);
    assert(compressed != NULL);

    int rc = compress(compressed, &dest_len, (const Bytef *)original, src_len);
    assert(rc == Z_OK);
    assert(dest_len > 0);

    uLong decomp_len = src_len;
    Bytef *decompressed = (Bytef *)malloc(decomp_len);
    assert(decompressed != NULL);

    rc = uncompress(decompressed, &decomp_len, compressed, dest_len);
    assert(rc == Z_OK);
    assert(strcmp((char *)decompressed, original) == 0);

    free(compressed);
    free(decompressed);
}

int main(void) {
    test_compress_decompress();
    printf("zlib compression test passed!\n");
    return 0;
}
